sealed class CopypasteException: Exception() {
    
    class EncryptionFailed(
        ) : CopypasteException() {
        override val message
            get() = ""
    }
    
    class DecryptionFailed(

        val `messageText`: kotlin.String
        ) : CopypasteException() {
        override val message
            get() = "message=${ `messageText` }"
    }

    class DatabaseException(

        val `messageText`: kotlin.String
        ) : CopypasteException() {
        override val message
            get() = "message=${ `messageText` }"
    }

    class InvalidKeyLength(
        ) : CopypasteException() {
        override val message
            get() = ""
    }

    class Panicked(

        val `messageText`: kotlin.String
        ) : CopypasteException() {
        override val message
            get() = "message=${ `messageText` }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<CopypasteException> {
        override fun lift(error_buf: RustBuffer.ByValue): CopypasteException = FfiConverterTypeCopypasteError.lift(error_buf)
    }

    
}

public object FfiConverterTypeCopypasteError : FfiConverterRustBuffer<CopypasteException> {
    override fun read(buf: ByteBuffer): CopypasteException {
        

        return when(buf.getInt()) {
            1 -> CopypasteException.EncryptionFailed()
            2 -> CopypasteException.DecryptionFailed(
                FfiConverterString.read(buf),
                )
            3 -> CopypasteException.DatabaseException(
                FfiConverterString.read(buf),
                )
            4 -> CopypasteException.InvalidKeyLength()
            5 -> CopypasteException.Panicked(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: CopypasteException): ULong {
        return when(value) {
            is CopypasteException.EncryptionFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is CopypasteException.DecryptionFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
            is CopypasteException.DatabaseException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
            is CopypasteException.InvalidKeyLength -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is CopypasteException.Panicked -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
        }
    }

    override fun write(value: CopypasteException, buf: ByteBuffer) {
        when(value) {
            is CopypasteException.EncryptionFailed -> {
                buf.putInt(1)
                Unit
            }
            is CopypasteException.DecryptionFailed -> {
                buf.putInt(2)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
            is CopypasteException.DatabaseException -> {
                buf.putInt(3)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
            is CopypasteException.InvalidKeyLength -> {
                buf.putInt(4)
                Unit
            }
            is CopypasteException.Panicked -> {
                buf.putInt(5)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}





sealed class VersionException: Exception() {
    
    class Incompatible(
        
        val `rustAbi`: kotlin.UInt, 
        
        val `kotlinAbi`: kotlin.UInt
        ) : VersionException() {
        override val message
            get() = "rustAbi=${ `rustAbi` }, kotlinAbi=${ `kotlinAbi` }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<VersionException> {
        override fun lift(error_buf: RustBuffer.ByValue): VersionException = FfiConverterTypeVersionError.lift(error_buf)
    }

    
}

public object FfiConverterTypeVersionError : FfiConverterRustBuffer<VersionException> {
    override fun read(buf: ByteBuffer): VersionException {
        

        return when(buf.getInt()) {
            1 -> VersionException.Incompatible(
                FfiConverterUInt.read(buf),
                FfiConverterUInt.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: VersionException): ULong {
        return when(value) {
            is VersionException.Incompatible -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterUInt.allocationSize(value.`rustAbi`)
                + FfiConverterUInt.allocationSize(value.`kotlinAbi`)
            )
        }
    }

    override fun write(value: VersionException, buf: ByteBuffer) {
        when(value) {
            is VersionException.Incompatible -> {
                buf.putInt(1)
                FfiConverterUInt.write(value.`rustAbi`, buf)
                FfiConverterUInt.write(value.`kotlinAbi`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




public object FfiConverterOptionalString: FfiConverterRustBuffer<kotlin.String?> {
    override fun read(buf: ByteBuffer): kotlin.String? {
        if (buf.get().toInt() == 0) {
            return null
        }
        return FfiConverterString.read(buf)
    }

    override fun allocationSize(value: kotlin.String?): ULong {
        if (value == null) {
            return 1UL
        } else {
            return 1UL + FfiConverterString.allocationSize(value)
        }
    }

    override fun write(value: kotlin.String?, buf: ByteBuffer) {
        if (value == null) {
            buf.put(0)
        } else {
            buf.put(1)
            FfiConverterString.write(value, buf)
        }
    }
}




public object FfiConverterSequenceUByte: FfiConverterRustBuffer<List<kotlin.UByte>> {
    override fun read(buf: ByteBuffer): List<kotlin.UByte> {
        val len = buf.getInt()
        return List<kotlin.UByte>(len) {
            FfiConverterUByte.read(buf)
        }
    }

    override fun allocationSize(value: List<kotlin.UByte>): ULong {
        val sizeForLength = 4UL
        val sizeForItems = value.map { FfiConverterUByte.allocationSize(it) }.sum()
        return sizeForLength + sizeForItems
    }

    override fun write(value: List<kotlin.UByte>, buf: ByteBuffer) {
        buf.putInt(value.size)
        value.iterator().forEach {
            FfiConverterUByte.write(it, buf)
        }
    }
}
